import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import API from '../services/api';
import Loader from '../components/Loader';

function LeadDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [lead, setLead] = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    API.get(`/leads/${id}`)
      .then((res) => setLead(res.data))
      .catch(() => setError('Failed to load lead details.'));
  }, [id]);

  if (error) return <div className="error-msg">{error}</div>;
  if (!lead) return <Loader />;

  return (
    <div>
      <button onClick={() => navigate('/leads')} className="btn-back">← Back to Leads</button>
      <h2>{lead.fullName}</h2>
      <div className="details-grid">
        <div><strong>Email:</strong> {lead.email}</div>
        <div><strong>Phone:</strong> {lead.phoneNumber}</div>
        <div><strong>Country:</strong> {lead.country}</div>
        <div><strong>Course:</strong> {lead.courseInterested}</div>
        <div><strong>Source:</strong> {lead.leadSource}</div>
        <div><strong>Counselor:</strong> {lead.assignedCounselor}</div>
        <div><strong>Status:</strong> {lead.leadStatus}</div>
        <div><strong>Priority:</strong> {lead.priority}</div>
        <div><strong>Notes:</strong> {lead.notes}</div>
      </div>
    </div>
  );
}

export default LeadDetails;
